import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String name = reader.readLine();

        // Sanitize and escape user input to prevent XSS
        name = sanitizeInput(name);

        System.out.println("Hello, " + name + "!"); // Safe output

        // This line will no longer render JavaScript code entered by the user
    }

    // Function to sanitize and escape user input
    private static String sanitizeInput(String input) {
        // Replace special characters with their HTML entity equivalents
        input = input.replace("&", "&amp;")
                     .replace("<", "&lt;")
                     .replace(">", "&gt;")
                     .replace("\"", "&quot;")
                     .replace("'", "&#x27;")
                     .replace("/", "&#x2F;");

        return input;
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
